import type { ShellCommand, ShellContext, ShellResult } from "../shell-types";
import type { MemoryVolume } from "../../memory-volume";
import { cdnImport } from "../../constants/cdn-urls";
import * as pathPolyfill from "../../polyfills/path";

// Pyodide 类型定义
interface Pyodide {
  runPython(code: string): void;
  runPythonAsync(code: string): Promise<void>;
  globals: any;
  FS: {
    mkdirTree(path: string): void;
    writeFile(path: string, data: string | Uint8Array, opts?: { encoding?: string }): void;
    readFile(path: string, opts?: { encoding?: string }): string | Uint8Array;
    unlink(path: string): void;
    rmdir(path: string): void;
    readdir(path: string): string[];
    stat(path: string): { mode: number; size: number; mtime: number };
    mount(mountpoint: string, opts: { root: string }): void;
    unmount(mountpoint: string): void;
  };
  setStdout(options: { batched: (text: string) => void }): void;
  setStderr(options: { batched: (text: string) => void }): void;
  setStdin(options: { stdin: () => string | null }): void;
}

let pyodideInstance: Pyodide | null = null;
let pyodideLoadPromise: Promise<Pyodide> | null = null;

async function loadPyodide(): Promise<Pyodide> {
  if (pyodideInstance) {
    return pyodideInstance;
  }
  if (pyodideLoadPromise) {
    return pyodideLoadPromise;
  }

  pyodideLoadPromise = (async () => {
    try {
      const pyodideModule = await cdnImport("https://cdn.jsdelivr.net/pyodide/v0.25.1/full/pyodide.mjs");
      const pyodide = await pyodideModule.loadPyodide({
        indexURL: "https://cdn.jsdelivr.net/pyodide/v0.25.1/full/",
      });
      pyodideInstance = pyodide;
      return pyodide;
    } catch (error) {
      pyodideLoadPromise = null;
      throw new Error(`Failed to load Pyodide: ${error instanceof Error ? error.message : String(error)}`);
    }
  })();

  return pyodideLoadPromise;
}

// 将 MemoryVolume 桥接到 Pyodide 的文件系统
function setupVolumeBridge(pyodide: Pyodide, volume: MemoryVolume, cwd: string): void {
  // 设置工作目录和 Python 路径
  const normalizedCwd = cwd || "/";
  const bridgeCode = `
import sys
import os

# 设置工作目录
try:
    os.chdir('${normalizedCwd.replace(/'/g, "\\'")}')
except:
    pass

# 设置 Python 路径
sys.path.insert(0, '${normalizedCwd.replace(/'/g, "\\'")}')
`;
  
  try {
    pyodide.runPython(bridgeCode);
  } catch (e) {
    // 忽略错误，继续执行
  }

  // 同步文件系统：从 MemoryVolume 到 Pyodide FS
  // 只同步工作目录及其子目录，避免同步整个文件系统
  function syncToPyodideFS(volumePath: string, pyodidePath: string, maxDepth: number = 10): void {
    if (maxDepth <= 0) return;
    
    try {
      if (volume.existsSync(volumePath)) {
        const stats = volume.statSync(volumePath);
        if (stats.isFile()) {
          const content = volume.readFileSync(volumePath);
          const dir = pathPolyfill.dirname(pyodidePath);
          if (dir !== "/" && dir !== ".") {
            try {
              pyodide.FS.mkdirTree(dir);
            } catch {
              // 目录可能已存在
            }
          }
          try {
            pyodide.FS.writeFile(pyodidePath, content);
          } catch {
            // 文件可能已存在，尝试覆盖
            try {
              pyodide.FS.unlink(pyodidePath);
              pyodide.FS.writeFile(pyodidePath, content);
            } catch {
              // 忽略错误
            }
          }
        } else if (stats.isDirectory()) {
          try {
            pyodide.FS.mkdirTree(pyodidePath);
          } catch {
            // 目录可能已存在
          }
          const entries = volume.readdirSync(volumePath);
          for (const entry of entries) {
            const volEntryPath = pathPolyfill.join(volumePath, entry);
            const pyEntryPath = pathPolyfill.join(pyodidePath, entry);
            syncToPyodideFS(volEntryPath, pyEntryPath, maxDepth - 1);
          }
        }
      }
    } catch (e) {
      // 忽略同步错误
    }
  }

  // 同步工作目录的文件到 Pyodide 的根目录
  // 这样 Python 可以访问当前工作目录的文件
  syncToPyodideFS(normalizedCwd, "/", 10);
}

// 从 Pyodide FS 同步回 MemoryVolume
// 只同步工作目录中可能被修改的文件
function syncFromPyodideFS(pyodide: Pyodide, volume: MemoryVolume, cwd: string): void {
  const normalizedCwd = cwd || "/";
  
  function syncDir(pyodidePath: string, volumePath: string, maxDepth: number = 10): void {
    if (maxDepth <= 0) return;
    
    try {
      const entries = pyodide.FS.readdir(pyodidePath);
      for (const entry of entries) {
        if (entry === "." || entry === "..") continue;
        const pyEntryPath = pyodidePath === "/" ? `/${entry}` : `${pyodidePath}/${entry}`;
        const volEntryPath = pathPolyfill.join(volumePath, entry);
        try {
          const stat = pyodide.FS.stat(pyEntryPath);
          if (stat.mode & 0o040000) {
            // 目录
            if (!volume.existsSync(volEntryPath)) {
              volume.mkdirSync(volEntryPath, { recursive: true });
            }
            syncDir(pyEntryPath, volEntryPath, maxDepth - 1);
          } else {
            // 文件 - 检查是否需要更新
            try {
              const content = pyodide.FS.readFile(pyEntryPath);
              if (content instanceof Uint8Array) {
                // 二进制文件
                volume.writeFileSync(volEntryPath, content);
              } else if (typeof content === "string") {
                // 文本文件
                volume.writeFileSync(volEntryPath, content);
              }
            } catch {
              // 忽略读取错误
            }
          }
        } catch {
          // 忽略错误
        }
      }
    } catch {
      // 忽略错误
    }
  }

  // 只同步根目录（对应工作目录）的内容
  syncDir("/", normalizedCwd, 10);
}

export function createPythonCommand(): ShellCommand {
  return {
    name: "python",
    async execute(args, ctx) {
      const { volume, cwd, env } = ctx;
      let stdout = "";
      let stderr = "";
      let exitCode = 0;

      // 收集参数
      let target: string | null = null;
      let evalCode: string | null = null;
      let stdin: string | null = null;
      const scriptArgs: string[] = [];
      let collectingArgs = false;

      for (let i = 0; i < args.length; i++) {
        if (collectingArgs) {
          scriptArgs.push(args[i]);
          continue;
        }
        if (args[i] === "-c" || args[i] === "--command") {
          evalCode = args[++i] ?? "";
        } else if (args[i] === "--version" || args[i] === "-V") {
          return { stdout: "Python 3.11.0 (Pyodide 0.25.1)\n", stderr: "", exitCode: 0 };
        } else if (args[i] === "--help" || args[i] === "-h") {
          return {
            stdout: "Usage: python [option] ... [-c cmd | file] [arg] ...\n",
            stderr: "",
            exitCode: 0,
          };
        } else if (args[i].startsWith("-")) {
          // 跳过其他选项
        } else {
          target = args[i];
          collectingArgs = true;
        }
      }

      try {
        const pyodide = await loadPyodide();

        // 设置 stdout/stderr 捕获
        pyodide.setStdout({
          batched: (text: string) => {
            stdout += text;
          },
        });
        pyodide.setStderr({
          batched: (text: string) => {
            stderr += text;
          },
        });

        // 设置工作目录和文件系统
        setupVolumeBridge(pyodide, volume, cwd);

        // 设置环境变量
        const envCode = Object.entries(env)
          .map(([k, v]) => `os.environ['${k.replace(/'/g, "\\'")}'] = '${String(v).replace(/'/g, "\\'")}'`)
          .join("\n");
        if (envCode) {
          try {
            pyodide.runPython(`import os\n${envCode}`);
          } catch {
            // 忽略环境变量设置错误
          }
        }

        // 设置 sys.argv
        const argvParts = ["python"];
        if (target) {
          argvParts.push(target);
          argvParts.push(...scriptArgs);
        } else if (evalCode) {
          argvParts.push("-c", evalCode);
          argvParts.push(...scriptArgs);
        }
        try {
          pyodide.runPython(`import sys\nsys.argv = ${JSON.stringify(argvParts)}`);
        } catch {
          // 忽略 argv 设置错误
        }

        // 执行代码
        if (evalCode !== null) {
          // -c 选项：执行代码字符串
          try {
            pyodide.runPython(evalCode);
          } catch (e: any) {
            const errorMsg = e?.message || String(e);
            if (!errorMsg.includes("SystemExit")) {
              stderr += `Error: ${errorMsg}\n`;
              exitCode = 1;
            } else {
              // SystemExit 可能包含退出码
              const match = errorMsg.match(/SystemExit\((\d+)\)/);
              if (match) {
                exitCode = parseInt(match[1], 10);
              }
            }
          }
        } else if (target) {
          // 执行文件
          const resolvedPath = target.startsWith("/")
            ? target
            : pathPolyfill.join(cwd, target);

          if (!volume.existsSync(resolvedPath)) {
            return {
              stdout: "",
              stderr: `python: can't open file '${target}': [Errno 2] No such file or directory\n`,
              exitCode: 1,
            };
          }

          const content = volume.readFileSync(resolvedPath, "utf8");
          try {
            // 使用 Pyodide 的 runPythonAsync 直接执行代码
            // 通过设置 __file__ 变量来模拟文件执行
            const escapedPath = resolvedPath.replace(/\\/g, "\\\\").replace(/'/g, "\\'");
            const escapedTarget = target.replace(/\\/g, "\\\\").replace(/'/g, "\\'");
            
            // 使用 base64 编码来安全地传递代码内容
            const codeBase64 = btoa(unescape(encodeURIComponent(content)));
            
            await pyodide.runPythonAsync(`
import sys
import base64
__file__ = '${escapedPath}'
code_str = base64.b64decode('${codeBase64}').decode('utf-8')
code = compile(code_str, '${escapedTarget}', 'exec')
exec(code, {'__name__': '__main__', '__file__': '${escapedPath}'})
`);
          } catch (e: any) {
            const errorMsg = e?.message || String(e);
            if (!errorMsg.includes("SystemExit")) {
              stderr += `Error: ${errorMsg}\n`;
              exitCode = 1;
            } else {
              const match = errorMsg.match(/SystemExit\((\d+)\)/);
              if (match) {
                exitCode = parseInt(match[1], 10);
              }
            }
          }
        } else {
          // 交互模式（REPL）- 这里简化处理
          return {
            stdout: "Python 3.11.0 (Pyodide 0.25.1)\nType \"help\", \"copyright\", \"credits\" or \"license\" for more information.\n",
            stderr: "",
            exitCode: 0,
          };
        }

        // 同步文件系统更改回 MemoryVolume
        syncFromPyodideFS(pyodide, volume, cwd);
      } catch (e: any) {
        return {
          stdout: "",
          stderr: `python: ${e?.message || String(e)}\n`,
          exitCode: 1,
        };
      }

      return { stdout, stderr, exitCode };
    },
  };
}
