import type { BuiltinFn, ShellContext } from "../shell-types";
import {
  ok,
  fail,
  EXIT_OK,
  EXIT_FAIL,
  resolvePath,
  parseArgs,
  pathModule,
  MONTHS_SHORT,
  MONTHS_LONG,
  DAYS_SHORT,
  DAYS_LONG,
} from "../shell-helpers";

// set by the registry so `which` and `type` can check builtins
let _builtins: Map<string, BuiltinFn> | null = null;

export function setBuiltinsRef(b: Map<string, BuiltinFn>): void {
  _builtins = b;
}

/* ------------------------------------------------------------------ */
/*  Commands                                                           */
/* ------------------------------------------------------------------ */

const exportCmd: BuiltinFn = (args, ctx) => {
  if (args.length === 0 || args[0] === "-p") {
    let out = "";
    for (const [k, v] of Object.entries(ctx.env)) {
      out += `declare -x ${k}="${v}"\n`;
    }
    return ok(out);
  }
  for (const arg of args) {
    if (arg.startsWith("-")) continue; // skip flags like -n
    const eq = arg.indexOf("=");
    if (eq > 0) {
      // export VAR=value
      ctx.env[arg.slice(0, eq)] = arg.slice(eq + 1);
    } else if (eq === 0) {
      // export =val — invalid, ignore
    } else {
      // export VAR (no =): keep existing value, mark as exported
      // in our flat env model, it's already "exported" by virtue of being in env
      // just ensure it's present (if not set, set to empty string like bash)
      if (!(arg in ctx.env)) ctx.env[arg] = "";
    }
  }
  return ok();
};

const unset: BuiltinFn = (args, ctx) => {
  const { flags, positional } = parseArgs(args, ["f", "v"]);
  for (const name of positional) delete ctx.env[name];
  void flags;
  return ok();
};

const envCmd: BuiltinFn = (args, ctx, stdin) => {
  // env [-i] [VAR=val ...] [cmd [args...]]
  let clearEnv = false;
  const envOverrides: Record<string, string> = {};
  const cmdArgs: string[] = [];
  let parsingEnv = true;

  for (let i = 0; i < args.length; i++) {
    const a = args[i];
    if (parsingEnv && a === "-i") { clearEnv = true; continue; }
    if (parsingEnv && a === "-") { clearEnv = true; continue; }
    if (parsingEnv && a === "--") { parsingEnv = false; continue; }
    if (parsingEnv && /^[A-Za-z_][A-Za-z0-9_]*=/.test(a)) {
      const eq = a.indexOf("=");
      envOverrides[a.slice(0, eq)] = a.slice(eq + 1);
    } else {
      parsingEnv = false;
      cmdArgs.push(...args.slice(i));
      break;
    }
  }

  if (cmdArgs.length > 0) {
    // run command with modified env — delegate back to interpreter via ctx
    const newEnv = clearEnv ? { ...envOverrides } : { ...ctx.env, ...envOverrides };
    // We can't easily invoke a sub-command here without the interpreter,
    // so store in ctx and return a signal for the interpreter to handle.
    // For now, just export the vars and indicate the command via a stub.
    Object.assign(ctx.env, newEnv);
    return fail(`env: cannot execute '${cmdArgs[0]}': not supported in this context\n`);
  }

  // No command: print environment
  const envToPrint = clearEnv ? envOverrides : { ...ctx.env, ...envOverrides };
  let out = "";
  for (const [k, v] of Object.entries(envToPrint)) out += `${k}=${v}\n`;
  return ok(out);
  void stdin;
};

const which: BuiltinFn = (args, ctx) => {
  if (args.length === 0) return fail("which: missing argument\n");

  const { flags } = parseArgs(args, ["a"]);
  const showAll = flags.has("a");
  const names = args.filter((a) => !a.startsWith("-"));

  let out = "";
  for (const name of names) {
    const found: string[] = [];

    if (_builtins?.has(name)) found.push(`${name}: shell built-in command`);

    const knownBins: Record<string, string> = {
      node: "/usr/local/bin/node",
      npm: "/usr/local/bin/npm",
      npx: "/usr/local/bin/npx",
      pnpm: "/usr/local/bin/pnpm",
      yarn: "/usr/local/bin/yarn",
      bun: "/usr/local/bin/bun",
      bunx: "/usr/local/bin/bunx",
    };
    if (knownBins[name]) found.push(knownBins[name]);

    const binPath = `/node_modules/.bin/${name}`;
    if (ctx.volume.existsSync(binPath)) found.push(binPath);

    const pathDirs = (ctx.env.PATH || "").split(":").filter(Boolean);
    for (const dir of pathDirs) {
      const candidate = `${dir}/${name}`;
      if (ctx.volume.existsSync(candidate)) {
        if (!found.includes(candidate)) found.push(candidate);
      }
    }

    if (found.length === 0) {
      out += `${name} not found\n`;
    } else if (showAll) {
      for (const f of found) out += f + "\n";
    } else {
      out += found[0] + "\n";
    }
  }
  return out.includes("not found")
    ? { stdout: out, stderr: "", exitCode: 1 }
    : ok(out);
};

const typeCmd: BuiltinFn = (args, ctx) => {
  if (args.length === 0) return fail("type: missing argument\n");
  const name = args[0];
  if (_builtins?.has(name)) return ok(`${name} is a shell builtin\n`);

  const w = which([name], ctx);
  if (typeof w === "object" && "exitCode" in w && w.exitCode === 0) {
    return ok(`${name} is ${w.stdout.trim()}\n`);
  }
  return fail(`type: ${name}: not found\n`);
};

const trueCmd: BuiltinFn = () => ok();
const falseCmd: BuiltinFn = () => EXIT_FAIL;

const exitCmd: BuiltinFn = (args) => {
  const code = args[0] ? parseInt(args[0], 10) : 0;
  return { stdout: "", stderr: "", exitCode: code };
};

const clear: BuiltinFn = () => ok("\x1b[2J\x1b[H");

/* ------------------------------------------------------------------ */
/*  test / [                                                           */
/* ------------------------------------------------------------------ */

function evalTest(args: string[], ctx: ShellContext): boolean {
  if (args.length === 0) return false;

  if (args[0] === "!") return !evalTest(args.slice(1), ctx);

  if (args[0] === "(" && args[args.length - 1] === ")") {
    return evalTest(args.slice(1, -1), ctx);
  }

  for (let i = 0; i < args.length; i++) {
    if (args[i] === "-o") {
      return (
        evalTest(args.slice(0, i), ctx) || evalTest(args.slice(i + 1), ctx)
      );
    }
  }
  for (let i = 0; i < args.length; i++) {
    if (args[i] === "-a") {
      return (
        evalTest(args.slice(0, i), ctx) && evalTest(args.slice(i + 1), ctx)
      );
    }
  }

  if (args.length === 1) return args[0].length > 0;

  if (args.length === 2) {
    const [flag, val] = args;
    const p = resolvePath(val, ctx.cwd);

    if (flag === "-f") {
      try { return ctx.volume.statSync(p).isFile(); } catch { return false; }
    }
    if (flag === "-d") {
      try { return ctx.volume.statSync(p).isDirectory(); } catch { return false; }
    }
    if (flag === "-e") return ctx.volume.existsSync(p);
    if (flag === "-L" || flag === "-h") return ctx.volume.existsSync(p);
    if (flag === "-s") {
      try { return ctx.volume.readFileSync(p).length > 0; } catch { return false; }
    }
    if (flag === "-r" || flag === "-w") return ctx.volume.existsSync(p);
    if (flag === "-x") {
      if (ctx.volume.existsSync(p)) {
        const ext = pathModule.extname(p);
        return ext === ".sh" || ext === "" || p.includes("/bin/");
      }
      return false;
    }
    if (flag === "-n") return val.length > 0;
    if (flag === "-z") return val.length === 0;
    if (flag === "-t") return false;
  }

  if (args.length === 3) {
    const [left, op, right] = args;
    if (op === "=" || op === "==") return left === right;
    if (op === "!=") return left !== right;
    if (op === "-eq") return parseInt(left) === parseInt(right);
    if (op === "-ne") return parseInt(left) !== parseInt(right);
    if (op === "-lt") return parseInt(left) < parseInt(right);
    if (op === "-le") return parseInt(left) <= parseInt(right);
    if (op === "-gt") return parseInt(left) > parseInt(right);
    if (op === "-ge") return parseInt(left) >= parseInt(right);

    if (op === "-nt" || op === "-ot" || op === "-ef") {
      try {
        const sl = ctx.volume.statSync(resolvePath(left, ctx.cwd));
        const sr = ctx.volume.statSync(resolvePath(right, ctx.cwd));
        if (op === "-nt") return (sl.mtimeMs || 0) > (sr.mtimeMs || 0);
        if (op === "-ot") return (sl.mtimeMs || 0) < (sr.mtimeMs || 0);
        if (op === "-ef")
          return resolvePath(left, ctx.cwd) === resolvePath(right, ctx.cwd);
      } catch {
        return false;
      }
    }
  }

  return false;
}

const test_cmd: BuiltinFn = (args, ctx) => {
  const testArgs = [...args];
  if (testArgs[testArgs.length - 1] === "]") testArgs.pop();
  return { stdout: "", stderr: "", exitCode: evalTest(testArgs, ctx) ? 0 : 1 };
};

/* ------------------------------------------------------------------ */
/*  date                                                               */
/* ------------------------------------------------------------------ */

function getTimezoneAbbr(d: Date): string {
  const str = d.toTimeString();
  const m = str.match(/\((.+?)\)/);
  if (m) {
    const words = m[1].split(" ");
    if (words.length === 1) return words[0];
    return words.map((w) => w[0]).join("");
  }
  const off = -d.getTimezoneOffset();
  const sign = off >= 0 ? "+" : "-";
  const h = String(Math.floor(Math.abs(off) / 60)).padStart(2, "0");
  const min = String(Math.abs(off) % 60).padStart(2, "0");
  return `${sign}${h}${min}`;
}

function formatDate(d: Date, fmt: string, utc: boolean): string {
  const g = utc
    ? {
        Y: d.getUTCFullYear(), m: d.getUTCMonth(), d: d.getUTCDate(),
        H: d.getUTCHours(), M: d.getUTCMinutes(), S: d.getUTCSeconds(),
        w: d.getUTCDay(),
      }
    : {
        Y: d.getFullYear(), m: d.getMonth(), d: d.getDate(),
        H: d.getHours(), M: d.getMinutes(), S: d.getSeconds(),
        w: d.getDay(),
      };
  let out = "";
  for (let i = 0; i < fmt.length; i++) {
    if (fmt[i] === "%" && i + 1 < fmt.length) {
      const s = fmt[++i];
      if (s === "Y") out += g.Y;
      else if (s === "y") out += String(g.Y).slice(-2);
      else if (s === "m") out += String(g.m + 1).padStart(2, "0");
      else if (s === "d") out += String(g.d).padStart(2, "0");
      else if (s === "e") out += String(g.d).padStart(2, " ");
      else if (s === "H") out += String(g.H).padStart(2, "0");
      else if (s === "M") out += String(g.M).padStart(2, "0");
      else if (s === "S") out += String(g.S).padStart(2, "0");
      else if (s === "I") out += String(g.H % 12 || 12).padStart(2, "0");
      else if (s === "p") out += g.H < 12 ? "AM" : "PM";
      else if (s === "P") out += g.H < 12 ? "am" : "pm";
      else if (s === "a") out += DAYS_SHORT[g.w];
      else if (s === "A") out += DAYS_LONG[g.w];
      else if (s === "b" || s === "h") out += MONTHS_SHORT[g.m];
      else if (s === "B") out += MONTHS_LONG[g.m];
      else if (s === "w") out += g.w;
      else if (s === "u") out += g.w === 0 ? 7 : g.w;
      else if (s === "j") {
        const jan1 = new Date(g.Y, 0, 1);
        const diff = d.getTime() - jan1.getTime();
        out += String(Math.floor(diff / 86400000) + 1).padStart(3, "0");
      } else if (s === "s") out += Math.floor(d.getTime() / 1000);
      else if (s === "N") out += String(d.getMilliseconds() * 1000000).padStart(9, "0");
      else if (s === "n") out += "\n";
      else if (s === "t") out += "\t";
      else if (s === "T")
        out += `${String(g.H).padStart(2, "0")}:${String(g.M).padStart(2, "0")}:${String(g.S).padStart(2, "0")}`;
      else if (s === "R")
        out += `${String(g.H).padStart(2, "0")}:${String(g.M).padStart(2, "0")}`;
      else if (s === "F")
        out += `${g.Y}-${String(g.m + 1).padStart(2, "0")}-${String(g.d).padStart(2, "0")}`;
      else if (s === "D")
        out += `${String(g.m + 1).padStart(2, "0")}/${String(g.d).padStart(2, "0")}/${String(g.Y).slice(-2)}`;
      else if (s === "Z") out += utc ? "UTC" : getTimezoneAbbr(d);
      else if (s === "%") out += "%";
      else out += "%" + s;
    } else {
      out += fmt[i];
    }
  }
  return out;
}

const date_cmd: BuiltinFn = (args) => {
  const { flags, opts, positional } = parseArgs(args, ["u", "R", "I"], ["d"]);
  const utc = flags.has("u");
  const rfc = flags.has("R");
  const iso = flags.has("I");
  const dateStr = opts["d"];

  const d = dateStr ? new Date(dateStr) : new Date();
  if (isNaN(d.getTime())) return fail(`date: invalid date '${dateStr}'\n`);

  const fmt = positional.find((a) => a.startsWith("+"));
  if (fmt) return ok(formatDate(d, fmt.slice(1), utc) + "\n");
  if (rfc) return ok(d.toUTCString() + "\n");
  if (iso) return ok(d.toISOString().slice(0, 10) + "\n");

  const day = DAYS_SHORT[utc ? d.getUTCDay() : d.getDay()];
  const mon = MONTHS_SHORT[utc ? d.getUTCMonth() : d.getMonth()];
  const date = utc ? d.getUTCDate() : d.getDate();
  const hh = String(utc ? d.getUTCHours() : d.getHours()).padStart(2, "0");
  const mm = String(utc ? d.getUTCMinutes() : d.getMinutes()).padStart(2, "0");
  const ss = String(utc ? d.getUTCSeconds() : d.getSeconds()).padStart(2, "0");
  const year = utc ? d.getUTCFullYear() : d.getFullYear();
  const tz = utc ? "UTC" : getTimezoneAbbr(d);

  return ok(
    `${day} ${mon} ${String(date).padStart(2, " ")} ${hh}:${mm}:${ss} ${tz} ${year}\n`,
  );
};

/* ------------------------------------------------------------------ */
/*  sleep                                                              */
/* ------------------------------------------------------------------ */

const sleep_cmd: BuiltinFn = async (args) => {
  const seconds = parseFloat(args[0] || "0");
  if (seconds > 0) await new Promise((r) => setTimeout(r, seconds * 1000));
  return ok();
};

/* ------------------------------------------------------------------ */
/*  read – read a line from stdin into variables                        */
/* ------------------------------------------------------------------ */

const read_cmd: BuiltinFn = (args, ctx, stdin) => {
  const vars: string[] = [];
  let raw = false;
  let prompt = "";
  let delim = "\n";

  for (let i = 0; i < args.length; i++) {
    if (args[i] === "-r") { raw = true; continue; }
    if (args[i] === "-p" && i + 1 < args.length) { prompt = args[++i]; continue; }
    if (args[i] === "-d" && i + 1 < args.length) { delim = args[++i]; continue; }
    if ((args[i] === "-t" || args[i] === "-n" || args[i] === "-N") && i + 1 < args.length) {
      i++; continue; // skip value
    }
    if (args[i] === "-s" || args[i] === "-e" || args[i] === "-u") continue;
    if (!args[i].startsWith("-")) vars.push(args[i]);
  }

  if (vars.length === 0) vars.push("REPLY");

  let line = "";
  let hasInput = false;

  if (stdin !== undefined && stdin !== "") {
    hasInput = true;
    if (delim === "\n") {
      const nl = stdin.indexOf("\n");
      line = nl >= 0 ? stdin.slice(0, nl) : stdin;
    } else {
      const di = stdin.indexOf(delim);
      line = di >= 0 ? stdin.slice(0, di) : stdin;
    }
    if (!raw) line = line.replace(/\\(.)/g, "$1");
  }

  if (vars.length === 1) {
    ctx.env[vars[0]] = line;
  } else {
    const parts = line.trim().split(/\s+/);
    for (let i = 0; i < vars.length - 1; i++) {
      ctx.env[vars[i]] = parts[i] ?? "";
    }
    ctx.env[vars[vars.length - 1]] = parts.slice(vars.length - 1).join(" ");
  }

  const stderr = prompt ? prompt : "";
  return { stdout: "", stderr, exitCode: hasInput ? 0 : 1 };
};

/* ------------------------------------------------------------------ */
/*  declare / local / typeset / readonly                               */
/* ------------------------------------------------------------------ */

const declare_cmd: BuiltinFn = (args, ctx) => {
  const { flags, positional } = parseArgs(args, ["i", "a", "A", "r", "x", "n", "l", "u", "p", "g", "f", "F"]);

  if (positional.length === 0 && !flags.has("p") && !flags.has("f") && !flags.has("F")) {
    // List all variables
    let out = "";
    for (const [k, v] of Object.entries(ctx.env)) {
      out += `declare -- ${k}="${v}"\n`;
    }
    return ok(out);
  }

  if (flags.has("f") || flags.has("F")) return ok(); // no functions in this shell

  for (const arg of positional) {
    const eq = arg.indexOf("=");
    if (eq > 0) {
      const name = arg.slice(0, eq);
      let val = arg.slice(eq + 1);
      if (flags.has("i")) val = String(parseInt(val) || 0);
      if (flags.has("l")) val = val.toLowerCase();
      if (flags.has("u")) val = val.toUpperCase();
      if (flags.has("x")) ctx.env[name] = val; // export
      else ctx.env[name] = val;
    } else {
      if (flags.has("p")) {
        const v = ctx.env[arg];
        if (v !== undefined) return ok(`declare -- ${arg}="${v}"\n`);
      }
      // Ensure variable exists (set to empty if not set)
      if (!(arg in ctx.env)) ctx.env[arg] = "";
    }
  }
  return ok();
};

const local_cmd: BuiltinFn = (args, ctx) => {
  // In a non-function context, behaves like declare
  for (const arg of args) {
    const eq = arg.indexOf("=");
    if (eq > 0) ctx.env[arg.slice(0, eq)] = arg.slice(eq + 1);
    else if (!(arg in ctx.env)) ctx.env[arg] = "";
  }
  return ok();
};

const readonly_cmd: BuiltinFn = (args, ctx) => {
  if (args.length === 0) {
    let out = "";
    for (const [k, v] of Object.entries(ctx.env)) out += `declare -r ${k}="${v}"\n`;
    return ok(out);
  }
  for (const arg of args) {
    const eq = arg.indexOf("=");
    if (eq > 0) ctx.env[arg.slice(0, eq)] = arg.slice(eq + 1);
  }
  return ok();
};

/* ------------------------------------------------------------------ */
/*  set – list or set shell variables / options                        */
/* ------------------------------------------------------------------ */

const set_cmd: BuiltinFn = (args, ctx) => {
  if (args.length === 0) {
    let out = "";
    for (const [k, v] of Object.entries(ctx.env)) out += `${k}=${v}\n`;
    return ok(out);
  }
  // -e, -u, -x, -o, +o etc are shell options we accept but ignore
  const opts = args.filter((a) => a.startsWith("-") || a.startsWith("+"));
  const positional = args.filter((a) => !a.startsWith("-") && !a.startsWith("+"));
  void opts;
  if (positional.length > 0) {
    // set positional params ($1, $2, ...) – store as _1, _2 etc
    positional.forEach((val, i) => { ctx.env[String(i + 1)] = val; });
  }
  return ok();
};

/* ------------------------------------------------------------------ */
/*  shopt / setopt – shell options (stub)                              */
/* ------------------------------------------------------------------ */

const shopt_cmd: BuiltinFn = () => ok();
const setopt_cmd: BuiltinFn = () => ok();

/* ------------------------------------------------------------------ */
/*  trap – signal traps (stub)                                         */
/* ------------------------------------------------------------------ */

const trap_cmd: BuiltinFn = () => ok();

/* ------------------------------------------------------------------ */
/*  getopts – option parsing                                           */
/* ------------------------------------------------------------------ */

const getopts_cmd: BuiltinFn = (args, ctx) => {
  if (args.length < 2) return fail("getopts: missing argument\n");
  const optstring = args[0];
  const varname = args[1];

  // Use OPTIND to track position
  let optind = parseInt(ctx.env.OPTIND || "1");
  const positional = Object.keys(ctx.env)
    .filter((k) => /^\d+$/.test(k))
    .sort((a, b) => parseInt(a) - parseInt(b))
    .map((k) => ctx.env[k]);

  if (optind > positional.length) {
    ctx.env[varname] = "?";
    ctx.env.OPTIND = "1";
    return EXIT_FAIL;
  }

  const arg = positional[optind - 1];
  if (!arg || !arg.startsWith("-") || arg === "--") {
    ctx.env[varname] = "?";
    return EXIT_FAIL;
  }

  const opt = arg[1];
  const optstringClean = optstring.replace(/^:/, "");
  if (!optstringClean.includes(opt)) {
    ctx.env[varname] = "?";
    ctx.env.OPTERR = "1";
    ctx.env.OPTIND = String(optind + 1);
    return EXIT_FAIL;
  }

  ctx.env[varname] = opt;
  // Check if this option takes an argument
  const idx = optstringClean.indexOf(opt);
  if (optstringClean[idx + 1] === ":") {
    const optarg = arg.length > 2 ? arg.slice(2) : positional[optind];
    ctx.env.OPTARG = optarg ?? "";
    ctx.env.OPTIND = String(optind + (arg.length > 2 ? 1 : 2));
  } else {
    ctx.env.OPTIND = String(optind + 1);
  }

  return ok();
};

/* ------------------------------------------------------------------ */
/*  Registry                                                           */
/* ------------------------------------------------------------------ */

export const shellEnvCommands: [string, BuiltinFn][] = [
  ["export", exportCmd],
  ["unset", unset],
  ["env", envCmd],
  ["which", which],
  ["type", typeCmd],
  ["true", trueCmd],
  ["false", falseCmd],
  [":", trueCmd],
  ["exit", exitCmd],
  ["clear", clear],
  ["test", test_cmd],
  ["[", test_cmd],
  ["date", date_cmd],
  ["sleep", sleep_cmd],
  // New shell/env builtins
  ["read", read_cmd],
  ["declare", declare_cmd],
  ["local", local_cmd],
  ["typeset", declare_cmd],
  ["readonly", readonly_cmd],
  ["set", set_cmd],
  ["shopt", shopt_cmd],
  ["setopt", setopt_cmd],
  ["trap", trap_cmd],
  ["getopts", getopts_cmd],
];
