import type { BuiltinFn } from "../shell-types";
import { ok, fail, resolvePath, parseArgs, humanSize } from "../shell-helpers";

/* ------------------------------------------------------------------ */
/*  stat                                                               */
/* ------------------------------------------------------------------ */

const stat_cmd: BuiltinFn = (args, ctx) => {
  const { flags, opts, positional } = parseArgs(args, ["L", "f", "t"], ["c"]);
  const fmt = opts["c"];
  const terse = flags.has("t");

  if (positional.length === 0) return fail("stat: missing operand\n");

  let out = "";
  for (const file of positional) {
    const p = resolvePath(file, ctx.cwd);
    try {
      const st = ctx.volume.statSync(p);
      const isDir = st.isDirectory();
      let size = 0;
      if (!isDir) {
        try {
          size = ctx.volume.readFileSync(p).length;
        } catch { /* */ }
      }
      const mtime = new Date(st.mtimeMs || Date.now());
      const iso = mtime.toISOString().replace("T", " ").slice(0, 19);
      const mode = isDir ? "drwxr-xr-x" : "-rw-r--r--";
      const type = isDir ? "directory" : "regular file";
      const blocks = Math.ceil(size / 512);

      if (fmt) {
        let f = fmt;
        f = f.replace(/%n/g, file);
        f = f.replace(/%N/g, `"${file}"`);
        f = f.replace(/%s/g, String(size));
        f = f.replace(/%b/g, String(blocks));
        f = f.replace(/%B/g, "512");
        f = f.replace(/%f/g, isDir ? "41ed" : "81a4");
        f = f.replace(/%A/g, mode);
        f = f.replace(/%F/g, type);
        f = f.replace(/%u/g, "1000");
        f = f.replace(/%g/g, "1000");
        f = f.replace(/%U/g, "user");
        f = f.replace(/%G/g, "user");
        f = f.replace(/%i/g, "0");
        f = f.replace(/%d/g, "0");
        f = f.replace(/%h/g, "1");
        f = f.replace(/%[xyz]/g, `${iso}.000000000 +0000`);
        f = f.replace(/%[XYZ]/g, String(Math.floor((st.mtimeMs || Date.now()) / 1000)));
        f = f.replace(/%%/g, "%");
        out += f + "\n";
      } else if (terse) {
        out += `${file} ${size} ${blocks} 0644 1000 1000 0 0 0 1 512\n`;
      } else {
        out += `  File: ${file}\n`;
        out += `  Size: ${size}\t\tBlocks: ${blocks}\t IO Block: 4096   ${type}\n`;
        out += `Device: 0\tInode: 0\t\tLinks: 1\n`;
        out += `Access: (0644/${mode})\tUid: (1000/ user)\tGid: (1000/ user)\n`;
        out += `Access: ${iso}.000000000 +0000\n`;
        out += `Modify: ${iso}.000000000 +0000\n`;
        out += `Change: ${iso}.000000000 +0000\n`;
        out += ` Birth: -\n`;
      }
    } catch {
      return fail(`stat: cannot stat '${file}': No such file or directory\n`);
    }
  }
  return ok(out);
};

/* ------------------------------------------------------------------ */
/*  du                                                                 */
/* ------------------------------------------------------------------ */

function getDirSize(ctx: Parameters<BuiltinFn>[1], dir: string): number {
  let total = 0;
  try {
    for (const name of ctx.volume.readdirSync(dir)) {
      const full = dir === "/" ? `/${name}` : `${dir}/${name}`;
      try {
        const st = ctx.volume.statSync(full);
        if (st.isDirectory()) {
          total += getDirSize(ctx, full);
        } else {
          try { total += ctx.volume.readFileSync(full).length; } catch { /* */ }
        }
      } catch { /* */ }
    }
  } catch { /* */ }
  return total;
}

const du_cmd: BuiltinFn = (args, ctx) => {
  const { flags, positional } = parseArgs(args, ["h", "s", "a", "k", "m", "b", "c"]);
  const human = flags.has("h");
  const summarize = flags.has("s");
  const megabytes = flags.has("m");
  const kilobytes = flags.has("k");
  const bytes_ = flags.has("b");
  const showTotal = flags.has("c");

  const targets = positional.length > 0 ? positional : ["."];

  const fmtSize = (n: number) => {
    if (human) return humanSize(n).padStart(4);
    if (bytes_) return String(n);
    if (megabytes) return String(Math.max(1, Math.ceil(n / 1048576)));
    if (kilobytes) return String(Math.max(1, Math.ceil(n / 1024)));
    return String(Math.max(1, Math.ceil(n / 512)));
  };

  let out = "";
  let grand = 0;

  const walkDir = (dir: string, label: string, depth: number) => {
    const entries: string[] = [];
    try {
      for (const name of ctx.volume.readdirSync(dir)) entries.push(name);
    } catch { return; }

    let dirTotal = 0;
    for (const name of entries) {
      const full = dir === "/" ? `/${name}` : `${dir}/${name}`;
      try {
        const st = ctx.volume.statSync(full);
        if (st.isDirectory()) {
          walkDir(full, `${label}/${name}`, depth + 1);
          dirTotal += getDirSize(ctx, full);
        } else {
          let sz = 0;
          try { sz = ctx.volume.readFileSync(full).length; } catch { /* */ }
          if (!summarize && flags.has("a")) out += `${fmtSize(sz)}\t${label}/${name}\n`;
          dirTotal += sz;
        }
      } catch { /* */ }
    }
    if (!summarize || depth === 0) {
      out += `${fmtSize(dirTotal)}\t${label}\n`;
    }
    if (depth === 0) grand += dirTotal;
  };

  for (const target of targets) {
    const p = resolvePath(target, ctx.cwd);
    try {
      const st = ctx.volume.statSync(p);
      if (st.isDirectory()) {
        if (summarize) {
          const sz = getDirSize(ctx, p);
          grand += sz;
          out += `${fmtSize(sz)}\t${target}\n`;
        } else {
          walkDir(p, target, 0);
        }
      } else {
        let sz = 0;
        try { sz = ctx.volume.readFileSync(p).length; } catch { /* */ }
        grand += sz;
        out += `${fmtSize(sz)}\t${target}\n`;
      }
    } catch {
      return fail(`du: cannot access '${target}': No such file or directory\n`);
    }
  }

  if (showTotal) out += `${fmtSize(grand)}\ttotal\n`;
  return ok(out);
};

/* ------------------------------------------------------------------ */
/*  df                                                                 */
/* ------------------------------------------------------------------ */

const df_cmd: BuiltinFn = (args) => {
  const { flags } = parseArgs(args, ["h", "H", "k", "m", "T"]);
  const human = flags.has("h") || flags.has("H");
  const showType = flags.has("T");

  const total = 10 * 1024 * 1024 * 1024; // 10 GB fake
  const used = 1 * 1024 * 1024 * 1024;
  const avail = total - used;
  const pct = Math.round((used / total) * 100);

  const fmt = (n: number) => {
    if (human) return humanSize(n).padStart(8);
    return String(Math.ceil(n / 1024)).padStart(9);
  };

  const typeCol = showType ? "tmpfs      " : "";
  const header = showType
    ? "Filesystem     Type      1K-blocks   Used  Available Use% Mounted on\n"
    : "Filesystem     1K-blocks   Used  Available Use% Mounted on\n";

  return ok(
    header +
      `wenode         ${typeCol}${fmt(total)} ${fmt(used)} ${fmt(avail)}  ${pct}% /\n`,
  );
};

/* ------------------------------------------------------------------ */
/*  uname                                                              */
/* ------------------------------------------------------------------ */

const uname_cmd: BuiltinFn = (args) => {
  const { flags } = parseArgs(args, ["a", "s", "n", "r", "v", "m", "p", "i", "o"]);

  if (flags.has("a")) {
    return ok("Linux wenode 5.15.0 #1 SMP x86_64 GNU/Linux\n");
  }

  const parts: string[] = [];
  if (flags.has("s") || flags.size === 0) parts.push("Linux");
  if (flags.has("n")) parts.push("wenode");
  if (flags.has("r")) parts.push("5.15.0");
  if (flags.has("v")) parts.push("#1 SMP");
  if (flags.has("m")) parts.push("x86_64");
  if (flags.has("p")) parts.push("x86_64");
  if (flags.has("i")) parts.push("x86_64");
  if (flags.has("o")) parts.push("GNU/Linux");

  return ok((parts.length ? parts.join(" ") : "Linux") + "\n");
};

/* ------------------------------------------------------------------ */
/*  whoami / id / logname / groups / hostname                          */
/* ------------------------------------------------------------------ */

const whoami_cmd: BuiltinFn = () => ok("user\n");
const logname_cmd: BuiltinFn = () => ok("user\n");
const hostname_cmd: BuiltinFn = (args) => {
  if (args.includes("-s")) return ok("wenode\n");
  if (args.includes("-f") || args.includes("--fqdn")) return ok("wenode.local\n");
  return ok("wenode\n");
};

const id_cmd: BuiltinFn = (args) => {
  const { flags, positional } = parseArgs(args, ["u", "g", "G", "n", "r"]);
  const user = positional[0] || "user";
  const nameMode = flags.has("n");

  if (flags.has("u")) return ok((nameMode ? user : "1000") + "\n");
  if (flags.has("g")) return ok((nameMode ? user : "1000") + "\n");
  if (flags.has("G")) return ok((nameMode ? user : "1000") + "\n");

  return ok(`uid=1000(${user}) gid=1000(${user}) groups=1000(${user})\n`);
};

const groups_cmd: BuiltinFn = () => ok("user\n");

/* ------------------------------------------------------------------ */
/*  nproc / uptime                                                     */
/* ------------------------------------------------------------------ */

const nproc_cmd: BuiltinFn = (args) => {
  const all = args.includes("--all");
  return ok((all ? "8" : "4") + "\n");
};

const uptime_cmd: BuiltinFn = (args) => {
  const { flags } = parseArgs(args, ["p", "s"]);
  const d = new Date();
  const hh = String(d.getHours()).padStart(2, "0");
  const mm = String(d.getMinutes()).padStart(2, "0");

  if (flags.has("s")) return ok("2024-01-01 00:00:00\n");
  if (flags.has("p")) return ok("up 1 day, 0 hours, 0 minutes\n");
  return ok(` ${hh}:${mm}:00 up 1 day, 0:00, 1 user, load average: 0.00, 0.00, 0.00\n`);
};

/* ------------------------------------------------------------------ */
/*  ps                                                                 */
/* ------------------------------------------------------------------ */

const ps_cmd: BuiltinFn = (args) => {
  const aux = args.includes("aux") || args.includes("-aux");
  const wide = args.some((a) => a === "f" || a === "-f");
  void wide;

  if (aux) {
    return ok(
      "USER       PID %CPU %MEM    VSZ   RSS TTY      STAT START   TIME COMMAND\n" +
        "user         1  0.0  0.0  10000  1000 ?        Ss   00:00   0:00 /bin/sh\n",
    );
  }
  return ok(
    "  PID TTY          TIME CMD\n" +
      "    1 pts/0    00:00:00 sh\n",
  );
};

/* ------------------------------------------------------------------ */
/*  kill / pkill / killall                                             */
/* ------------------------------------------------------------------ */

const kill_cmd: BuiltinFn = (args) => {
  if (args.includes("-l") || args.includes("--list")) {
    return ok(
      " 1 HUP  2 INT  3 QUIT  6 ABRT  9 KILL 15 TERM 17 CHLD 18 CONT 19 STOP\n",
    );
  }
  return ok();
};

const pkill_cmd: BuiltinFn = () => ok();
const killall_cmd: BuiltinFn = () => ok();

/* ------------------------------------------------------------------ */
/*  jobs / wait                                                        */
/* ------------------------------------------------------------------ */

const jobs_cmd: BuiltinFn = () => ok();
const wait_cmd: BuiltinFn = () => ok();

/* ------------------------------------------------------------------ */
/*  umask                                                              */
/* ------------------------------------------------------------------ */

let _umask = "0022";
const umask_cmd: BuiltinFn = (args) => {
  const { flags, positional } = parseArgs(args, ["S", "p"]);
  if (positional.length > 0) {
    _umask = positional[0];
    return ok();
  }
  if (flags.has("S")) {
    // symbolic: 0022 → u=rwx,g=rx,o=rx
    return ok("u=rwx,g=rx,o=rx\n");
  }
  return ok(_umask + "\n");
};

/* ------------------------------------------------------------------ */
/*  ulimit                                                             */
/* ------------------------------------------------------------------ */

const ulimit_cmd: BuiltinFn = (args) => {
  const { flags } = parseArgs(args, ["a", "n", "f", "u", "v", "s", "c", "d", "l", "m", "t", "H", "S"]);
  if (flags.has("a")) {
    return ok(
      "core file size          (blocks, -c) 0\n" +
        "data seg size           (kbytes, -d) unlimited\n" +
        "file size               (blocks, -f) unlimited\n" +
        "open files                      (-n) 1024\n" +
        "stack size              (kbytes, -s) 8192\n" +
        "cpu time               (seconds, -t) unlimited\n" +
        "virtual memory          (kbytes, -v) unlimited\n",
    );
  }
  if (flags.has("n")) return ok("1024\n");
  return ok("unlimited\n");
};

/* ------------------------------------------------------------------ */
/*  tput / stty                                                        */
/* ------------------------------------------------------------------ */

const tput_cmd: BuiltinFn = (args) => {
  const cap = args[0];
  if (!cap) return ok();
  if (cap === "cols" || cap === "columns") return ok("80\n");
  if (cap === "lines" || cap === "rows") return ok("24\n");
  if (cap === "colors") return ok("256\n");
  if (cap === "sgr0" || cap === "op" || cap === "el" || cap === "el1") return ok("");
  if (cap === "setaf" || cap === "setab") return ok("");
  if (cap === "bold" || cap === "dim" || cap === "rev" || cap === "smso" || cap === "rmso") return ok("");
  if (cap === "cup") return ok(""); // cursor position
  if (cap === "clear") return ok("\x1b[2J\x1b[H");
  if (cap === "civis" || cap === "cnorm") return ok("");
  return ok();
};

const stty_cmd: BuiltinFn = (args) => {
  if (args.includes("-a") || args.includes("all")) {
    return ok("speed 38400 baud; rows 24; columns 80; line = 0;\n");
  }
  if (args.includes("size")) return ok("24 80\n");
  return ok();
};

/* ------------------------------------------------------------------ */
/*  mktemp                                                             */
/* ------------------------------------------------------------------ */

const mktemp_cmd: BuiltinFn = (args, ctx) => {
  const { flags, positional } = parseArgs(args, ["d", "u", "p", "q"], ["p", "t", "suffix"]);
  const isDir = flags.has("d");
  const template = positional[0] || "tmp.XXXXXX";

  // Replace trailing X's with random chars
  const rand = () => Math.random().toString(36).slice(2, 8);
  const name = template.replace(/X{3,}$/, () => rand().slice(0, template.match(/X+$/)?.[0].length ?? 6));
  const base = ctx.env.TMPDIR || "/tmp";
  const p = `${base}/${name}`;

  try {
    ctx.volume.mkdirSync(base, { recursive: true });
    if (isDir) {
      ctx.volume.mkdirSync(p, { recursive: true });
    } else {
      ctx.volume.writeFileSync(p, "");
    }
    return ok(p + "\n");
  } catch (e) {
    return fail(`mktemp: failed to create: ${e instanceof Error ? e.message : String(e)}\n`);
  }
};

/* ------------------------------------------------------------------ */
/*  time                                                               */
/* ------------------------------------------------------------------ */

const time_cmd: BuiltinFn = async (args, ctx) => {
  if (args.length === 0) return ok();
  const start = Date.now();
  const result = await ctx.exec(args.join(" "), { cwd: ctx.cwd, env: ctx.env });
  const elapsed = (Date.now() - start) / 1000;
  const fmt = elapsed.toFixed(3);
  return {
    stdout: result.stdout,
    stderr:
      result.stderr +
      `\nreal\t0m${fmt}s\nuser\t0m0.000s\nsys\t0m0.000s\n`,
    exitCode: result.exitCode,
  };
};

/* ------------------------------------------------------------------ */
/*  timeout                                                            */
/* ------------------------------------------------------------------ */

const timeout_cmd: BuiltinFn = async (args, ctx) => {
  const { flags, positional } = parseArgs(args, ["k", "s", "foreground", "preserve-status"], ["k", "s"]);
  void flags;
  if (positional.length < 2) return fail("timeout: missing operand\n");

  const seconds = parseFloat(positional[0]);
  const cmd = positional.slice(1).join(" ");

  type R = { stdout: string; stderr: string; exitCode: number };
  const result = await Promise.race([
    ctx.exec(cmd, { cwd: ctx.cwd, env: ctx.env }),
    new Promise<R>((resolve) =>
      setTimeout(
        () => resolve({ stdout: "", stderr: "", exitCode: 124 }),
        seconds * 1000,
      ),
    ),
  ]);
  return result;
};

/* ------------------------------------------------------------------ */
/*  nohup                                                              */
/* ------------------------------------------------------------------ */

const nohup_cmd: BuiltinFn = async (args, ctx) => {
  if (args.length === 0) return fail("nohup: missing operand\n");
  return ctx.exec(args.join(" "), { cwd: ctx.cwd, env: ctx.env });
};

/* ------------------------------------------------------------------ */
/*  tee (also handles -a via file-ops, but add a pager stub)          */
/* ------------------------------------------------------------------ */

const watch_cmd: BuiltinFn = async (args, ctx) => {
  // Just run once; we can't do live watching in VFS
  const cmdArgs = args.filter((a) => !a.startsWith("-"));
  if (cmdArgs.length === 0) return fail("watch: missing command\n");
  return ctx.exec(cmdArgs.join(" "), { cwd: ctx.cwd, env: ctx.env });
};

/* ------------------------------------------------------------------ */
/*  printenv                                                           */
/* ------------------------------------------------------------------ */

const printenv_cmd: BuiltinFn = (args, ctx) => {
  if (args.length === 0) {
    let out = "";
    for (const [k, v] of Object.entries(ctx.env)) out += `${k}=${v}\n`;
    return ok(out);
  }
  let out = "";
  let exitCode = 0;
  for (const name of args) {
    const val = ctx.env[name];
    if (val !== undefined) {
      out += val + "\n";
    } else {
      exitCode = 1;
    }
  }
  return { stdout: out, stderr: "", exitCode };
};

/* ------------------------------------------------------------------ */
/*  arch / machine                                                     */
/* ------------------------------------------------------------------ */

const arch_cmd: BuiltinFn = () => ok("x86_64\n");

/* ------------------------------------------------------------------ */
/*  free                                                               */
/* ------------------------------------------------------------------ */

const free_cmd: BuiltinFn = (args) => {
  const { flags } = parseArgs(args, ["h", "m", "g", "k", "b", "t"]);
  const human = flags.has("h");
  const mega = flags.has("m");
  const giga = flags.has("g");

  const total = 8 * 1024; // 8 GB in MB
  const used = 2 * 1024;
  const free_ = total - used;
  const buffers = 256;
  const cached = 512;
  const available = free_ + buffers + cached;

  const fmt = (n: number) => {
    if (human) return humanSize(n * 1024 * 1024).padStart(8);
    if (giga) return String(Math.ceil(n / 1024)).padStart(8);
    if (mega) return String(n).padStart(8);
    return String(n * 1024).padStart(12); // kB
  };

  const unit = human ? "" : mega ? "Mi" : giga ? "Gi" : "";
  void unit;

  return ok(
    `              total        used        free      shared  buff/cache   available\n` +
      `Mem:      ${fmt(total)} ${fmt(used)} ${fmt(free_)}       0 ${fmt(buffers + cached)} ${fmt(available)}\n` +
      `Swap:     ${fmt(2048)}       ${fmt(0)} ${fmt(2048)}\n`,
  );
};

